        UserProfile* profile = new UserProfile();
        profile->id = user_ptr->id;
        profile->username = user_ptr->username;
        profile->email = user_ptr->email;
        profile->age = user_ptr->age;
        profile->is_active = user_ptr->is_active;
        
        return profile;
